#include "interface.h"

#include <omp.h>
#include <cstdint>
#include <vector>

namespace {

inline int num_threads() {
  int mt = omp_get_max_threads();
  if (mt < 1) return 1;
  return mt > 8 ? 8 : mt;
}

inline uint64_t checksum_u32_ptr(const uint32_t* data, int n) {
  uint64_t hash = 1469598103934665603ULL;
  for (int i = 0; i < n; ++i) {
    hash ^= static_cast<uint64_t>(data[i]);
    hash *= 1099511628211ULL;
  }
  return hash;
}

}  // namespace

uint64_t histogram_checksum(const std::vector<uint8_t>& input, int bins, int iters) {
  omp_set_num_threads(num_threads());

  if (bins <= 0) {
    return 1469598103934665603ULL;
  }

  std::vector<uint32_t> counts(static_cast<std::size_t>(bins), 0u);

  const int max_threads = num_threads();

  // Pad each thread-local histogram to reduce false sharing between adjacent
  // thread blocks. For the target workload bins is 256, but keep it generic.
  const int pad = 16;
  const int stride = bins + pad;
  std::vector<uint32_t> locals(static_cast<std::size_t>(max_threads) * static_cast<std::size_t>(stride), 0u);

  const uint8_t* in = input.empty() ? nullptr : input.data();
  const std::size_t n = input.size();

  for (int iter = 0; iter < iters; ++iter) {
#pragma omp parallel
    {
      const int tid = omp_get_thread_num();
      uint32_t* local = locals.data() + static_cast<std::size_t>(tid) * static_cast<std::size_t>(stride);

      for (int b = 0; b < bins; ++b) local[b] = 0u;

#pragma omp for schedule(static)
      for (std::size_t i = 0; i < n; ++i) {
        ++local[static_cast<int>(in[i])];
      }

#pragma omp for schedule(static)
      for (int b = 0; b < bins; ++b) {
        uint32_t sum = 0u;
        for (int t = 0; t < max_threads; ++t) {
          sum += locals[static_cast<std::size_t>(t) * static_cast<std::size_t>(stride) + static_cast<std::size_t>(b)];
        }
        counts[static_cast<std::size_t>(b)] = sum;
      }
    }
  }

  return checksum_u32_ptr(counts.data(), bins);
}
